DISTURBANCES - NATURAL

Fires

# Fires: clip and rasterize
fires &lt;- vect(bpdata, 'fires') |&gt;
  crop(vect(bnd)) |&gt;
  rasterize(rast30m) |&gt;
  mask(rast30m)
fires &lt;- subst(fires, NA, 0) |&gt;
  mask(rast30m)
names(fires) &lt;- "fires"
writeRaster(fires, '../data/raster30/fires.tif', overwrite=TRUE)
plot(fires)
